    '컴퍼니케이(307930)의 실제 일봉 데이터에서 상승장악형 스코어 88.0점을 통과한 구간입니다. 52주 신고가 대비 20% 이상 내려온 위치에서 음봉 뒤 양봉이 몸통을 완전히 감싸고, 두 봉 모두 앞뒤 10봉 저가 비교 하위 3개 안에 있으며, 양봉 바로 다음 봉까지의 구조를 기준으로 선별했습니다. 실제 다음 5봉 종가 기준 등락률은 -14.6%로, 정답은 하락입니다.',
    88.00,
    '["음봉 다음 양봉 몸통 장악","하단/상단 장악 여유율 15.0% / 200.0%","양봉 몸통/음봉 몸통 비율 3.15배","52주 최고 종가 대비 하락률 45.4%","음봉 꼬리 합 25.9%","양봉 꼬리 합 1.6%","음봉/양봉 저가 순위(앞뒤 10봉) 2위 / 3위","다음 봉 종가/기준 종가 여유 41.6%"]'::jsonb,
    '{"engulfing_completion":25,"body_ratio":15,"location_drawdown":20,"bearish_wick_quality":8,"bullish_wick_quality":20}'::jsonb,
    '[{"time":"2024-02-27","label":"음봉","position":"belowBar","shape":"circle","color":"#3b82f6"},{"time":"2024-02-28","label":"양봉 장악","position":"belowBar","shape":"arrowUp","color":"#ef4444"},{"time":"2024-02-29","label":"다음 봉","position":"aboveBar","shape":"circle","color":"#a855f7"}]'::jsonb
  )
  ) AS rq(id, symbol, source_symbol, source_exchange, source_url, source_date_range, difficulty, base_date, chart_data, actual_next_candles, correct_answer, ai_explanation, rule_score, pattern_evidence, pattern_score_breakdown, pattern_markers)
)
INSERT INTO questions (
  id,
  pattern_id,
  symbol,
  market,
  timeframe,
  difficulty,
  market_regime,
  base_date,
  chart_data,
  actual_next_candles,
  correct_answer,
  ai_explanation,
  rule_score,
  public_accuracy,
  pattern_evidence,
  pattern_score_breakdown,
  pattern_markers,
  is_synthetic,
  source_name,
  source_url,
  source_symbol,
  source_exchange,
  source_date_range
)
SELECT
  rq.id,
  p.id,
  rq.symbol,
  'KRX',
  '1d',
  rq.difficulty,
  'sideways'::market_regime,
  rq.base_date,
  rq.chart_data,
  rq.actual_next_candles,
  rq.correct_answer,
  rq.ai_explanation,
  rq.rule_score,
  0.7000,
  rq.pattern_evidence,
  rq.pattern_score_breakdown,
  rq.pattern_markers,
  false,
  'Yahoo Finance chart API',
  rq.source_url,
  rq.source_symbol,
  rq.source_exchange,
  rq.source_date_range
FROM real_questions rq
CROSS JOIN pattern_row p
ON CONFLICT (id) DO UPDATE SET
  pattern_id = EXCLUDED.pattern_id,
  symbol = EXCLUDED.symbol,
  market = EXCLUDED.market,
  timeframe = EXCLUDED.timeframe,
  difficulty = EXCLUDED.difficulty,
  market_regime = EXCLUDED.market_regime,
  base_date = EXCLUDED.base_date,
  chart_data = EXCLUDED.chart_data,
  actual_next_candles = EXCLUDED.actual_next_candles,
  correct_answer = EXCLUDED.correct_answer,
  ai_explanation = EXCLUDED.ai_explanation,
  rule_score = EXCLUDED.rule_score,
  public_accuracy = EXCLUDED.public_accuracy,
  pattern_evidence = EXCLUDED.pattern_evidence,
  pattern_score_breakdown = EXCLUDED.pattern_score_breakdown,
  pattern_markers = EXCLUDED.pattern_markers,
  is_synthetic = EXCLUDED.is_synthetic,
  source_name = EXCLUDED.source_name,
  source_url = EXCLUDED.source_url,
  source_symbol = EXCLUDED.source_symbol,
  source_exchange = EXCLUDED.source_exchange,
  source_date_range = EXCLUDED.source_date_range,
  is_active = true,
  updated_at = now();


UPDATE questions
SET is_active = false,
    updated_at = now()
WHERE pattern_id = (SELECT id FROM patterns WHERE slug = 'bullish-engulfing' LIMIT 1)
  AND source_name = 'Yahoo Finance chart API'
  AND is_synthetic = false
  AND id NOT IN ('31000000-0000-0000-0000-000000000001'::uuid, '31000000-0000-0000-0000-000000000002'::uuid, '31000000-0000-0000-0000-000000000003'::uuid, '31000000-0000-0000-0000-000000000004'::uuid, '31000000-0000-0000-0000-000000000005'::uuid, '31000000-0000-0000-0000-000000000006'::uuid, '31000000-0000-0000-0000-000000000007'::uuid, '31000000-0000-0000-0000-000000000008'::uuid, '31000000-0000-0000-0000-000000000009'::uuid, '31000000-0000-0000-0000-000000000010'::uuid);
